#include<bits/stdc++.h>
using namespace std;
int main(){
    int t;
        cin>>t;
    while(t--){
        string n;
        long long ans=0;
        long xian=1;
        cin>>n;

        for(int i=n.size()-1;i>=0;i--){
            if(n[i]<='6'){

                ans+= ((n[i]-'0') * xian);
            }else{
                ans+= ((n[i]-'1') *xian);
            }
            xian*=9;
        }
        cout<<ans<<"\n";
    }
    return 0;
}
